// Taken from the c-compiler's libc/besm6/unix/frexp.s, unchanged.  It is a b6as
// port of that project's libc/besm6/madlen/frexp.madlen (generated by U2; see the
// Madlen original for full commentary).
//
// It is here, and not in the libm of lib phase 7, because the CONVERSIONS need it:
// atof() is what calls it, and ecvt() and the printf engine call its companion
// modf().  A .s and not a .S: no extracode, so nothing to preprocess.
//
// double frexp(double value, int *exp) -- split value = fraction * 2^(*exp),
// with 0.5 <= |fraction| < 1, or fraction = 0 (and *exp = 0) when value = 0.
// Entry: value at mem[r15-1], exp pointer in the accumulator.  Fraction in the accumulator.
//
    .text
    .globl frexp
frexp:
    sti 14                  // r14 := exp ; A := value ; r15 -= 1
 14 atx                     // *exp := 0
 13 uza                     // value == 0  ->  fraction 0, *exp 0
 15 atx                     // push value : value now at mem[r15-1]

// --- *exp := exponent_field(value) - 64 ---
    asn 64+41               // A := value >> 41 ; the 7-bit field lands in bits 7-1
    aax #0177               // isolate the field (0..127)
    a-x #0100               // r1 := field - 64 = e
 14 stx                     // *exp := e ; pop value from stack

// --- fraction := value with the exponent field forced to 64 ---
    aax #037'7777'7777'7777 // keep sign + mantissa (bits 41-1)
    aox #0'40               // set the exponent field to 64 (bit 48)
 13 uj                      // return the fraction in A
